            new() { Title="Trie 樹實作", Description="實作 Trie（前綴樹），插入 \"apple\", \"app\", \"apply\"。判斷並輸出：Search(\"app\") 是否存在，StartsWith(\"appl\") 是否有前綴，Search(\"application\") 是否存在。每行輸出 true/false。", StarterCode="using System;\nusing System.Collections.Generic;\nclass TrieNode {\n    public Dictionary<char, TrieNode> Children = new();\n    public bool IsEnd;\n}\nclass Trie {\n    TrieNode root = new();\n    public void Insert(string word) { /* 實作 */ }\n    public bool Search(string word) { return false; }\n    public bool StartsWith(string prefix) { return false; }\n}\nclass Program {\n    static void Main() {\n        var t = new Trie();\n        t.Insert(\"apple\"); t.Insert(\"app\"); t.Insert(\"apply\");\n        Console.WriteLine(t.Search(\"app\"));\n        Console.WriteLine(t.StartsWith(\"appl\"));\n        Console.WriteLine(t.Search(\"application\"));\n    }\n}", SampleOutput="true\ntrue\nfalse", ValidationKeywords="TrieNode,Children,Insert,Search,StartsWith,IsEnd", Difficulty="advanced", TimeLimitSeconds=60 },
            new() { Title="觀察者模式", Description="實作觀察者模式：建立 EventBus，訂閱 \"click\" 事件的兩個 handler（分別輸出 \"Handler1: click\" 和 \"Handler2: click\"），觸發 \"click\" 事件，依序輸出兩個 handler 的訊息。", StarterCode="using System;\nusing System.Collections.Generic;\nclass EventBus {\n    Dictionary<string, List<Action<string>>> handlers = new();\n    public void Subscribe(string evt, Action<string> handler) { /* 實作 */ }\n    public void Publish(string evt) { /* 實作 */ }\n}\nclass Program {\n    static void Main() {\n        var bus = new EventBus();\n        bus.Subscribe(\"click\", e => Console.WriteLine($\"Handler1: {e}\"));\n        bus.Subscribe(\"click\", e => Console.WriteLine($\"Handler2: {e}\"));\n        bus.Publish(\"click\");\n    }\n}", SampleOutput="Handler1: click\nHandler2: click", ValidationKeywords="Dictionary,List,Action,Subscribe,Publish,handler,Console.Write", Difficulty="advanced", TimeLimitSeconds=60 },
            new() { Title="策略模式", Description="實作策略模式，定義排序策略介面，實作「升序」和「降序」兩種策略，對 {5,2,8,1,9} 分別套用後輸出（空格分隔，各一行）。", StarterCode="using System;\nusing System.Linq;\ninterface ISortStrategy {\n    int[] Sort(int[] data);\n}\nclass AscSort : ISortStrategy {\n    public int[] Sort(int[] data) { /* 升序 */ return data; }\n}\nclass DescSort : ISortStrategy {\n    public int[] Sort(int[] data) { /* 降序 */ return data; }\n}\nclass Sorter {\n    ISortStrategy strategy;\n    public Sorter(ISortStrategy s) { strategy = s; }\n    public void Execute(int[] data) { Console.WriteLine(string.Join(\" \", strategy.Sort(data))); }\n}\nclass Program {\n    static void Main() {\n        int[] data = {5,2,8,1,9};\n        new Sorter(new AscSort()).Execute(data);\n        new Sorter(new DescSort()).Execute(data);\n    }\n}", SampleOutput="1 2 5 8 9\n9 8 5 2 1", ValidationKeywords="ISortStrategy,AscSort,DescSort,OrderBy,OrderByDescending,strategy,Console.Write", Difficulty="advanced", TimeLimitSeconds=60 },
            new() { Title="並行安全 Counter", Description="使用 Interlocked 實作執行緒安全計數器，啟動 10 個執行緒各自 Increment 100 次，最後輸出總計數（應為 1000）。", StarterCode="using System;\nusing System.Threading;\nclass SafeCounter {\n    int count = 0;\n    public void Increment() {\n        // 使用 Interlocked 安全遞增\n    }\n    public int Value => count;\n}\nclass Program {\n    static void Main() {\n        var counter = new SafeCounter();\n        var threads = new Thread[10];\n        for (int i = 0; i < 10; i++) {\n            threads[i] = new Thread(() => { for(int j=0;j<100;j++) counter.Increment(); });\n        }\n        foreach (var t in threads) t.Start();\n        foreach (var t in threads) t.Join();\n        Console.WriteLine(counter.Value);\n    }\n}", SampleOutput="1000", ValidationKeywords="Interlocked,Increment,Thread,Start,Join,Console.Write,1000", Difficulty="advanced", TimeLimitSeconds=60 },
            new() { Title="泛型倉儲模式", Description="實作泛型 Repository<T>，包含 Add、GetById、GetAll 方法，使用 Dictionary 儲存。測試：加入 3 個 {Id,Name} 物件，GetAll 輸出所有名稱（每行一個）。", StarterCode="using System;\nusing System.Collections.Generic;\nclass Entity { public int Id; public string Name = \"\"; }\nclass Repository<T> where T : Entity {\n    Dictionary<int, T> store = new();\n    public void Add(T item) { /* 實作 */ }\n    public T? GetById(int id) { return null; }\n    public IEnumerable<T> GetAll() { return store.Values; }\n}\nclass Program {\n    static void Main() {\n        var repo = new Repository<Entity>();\n        repo.Add(new Entity{Id=1,Name=\"Alice\"});\n        repo.Add(new Entity{Id=2,Name=\"Bob\"});\n        repo.Add(new Entity{Id=3,Name=\"Charlie\"});\n        foreach (var e in repo.GetAll()) Console.WriteLine(e.Name);\n    }\n}", SampleOutput="Alice\nBob\nCharlie", ValidationKeywords="Repository,Dictionary,Add,GetAll,where T,Console.Write", Difficulty="advanced", TimeLimitSeconds=60 },
            new() { Title="實作迭代器模式", Description="實作自訂迭代器，建立 NumberRange 類別，實作 IEnumerable<int>，可用 foreach 遍歷指定範圍的偶數。輸出 2 到 10 的所有偶數（空格分隔）。", StarterCode="using System;\nusing System.Collections;\nusing System.Collections.Generic;\nclass NumberRange : IEnumerable<int> {\n    int start, end;\n    public NumberRange(int s, int e) { start=s; end=e; }\n    public IEnumerator<int> GetEnumerator() {\n        // 只 yield 偶數\n    }\n    IEnumerator IEnumerable.GetEnumerator() => GetEnumerator();\n}\nclass Program {\n    static void Main() {\n        var range = new NumberRange(2, 10);\n        Console.WriteLine(string.Join(\" \", range));\n    }\n}", SampleOutput="2 4 6 8 10", ValidationKeywords="IEnumerable,yield return,GetEnumerator,% 2,Console.Write,2 4 6 8 10", Difficulty="advanced", TimeLimitSeconds=60 },
            new() { Title="依賴注入容器", Description="實作簡單 DI 容器，支援 Register<TInterface, TImpl> 和 Resolve<T> 方法（使用 Activator.CreateInstance 建立實例）。測試：註冊並解析 ILogger → ConsoleLogger，呼叫 Log(\"Hello DI\") 輸出訊息。", StarterCode="using System;\nusing System.Collections.Generic;\ninterface ILogger { void Log(string msg); }\nclass ConsoleLogger : ILogger { public void Log(string msg) => Console.WriteLine(msg); }\nclass Container {\n    Dictionary<Type, Type> map = new();\n    public void Register<TI, TImpl>() { map[typeof(TI)] = typeof(TImpl); }\n    public T Resolve<T>() {\n        // 使用 Activator.CreateInstance 建立 TImpl 實例\n        return default!;\n    }\n}\nclass Program {\n    static void Main() {\n        var c = new Container();\n        c.Register<ILogger, ConsoleLogger>();\n        var logger = c.Resolve<ILogger>();\n        logger.Log(\"Hello DI\");\n    }\n}", SampleOutput="Hello DI", ValidationKeywords="Dictionary,Activator.CreateInstance,Register,Resolve,typeof,Console.Write,Hello DI", Difficulty="advanced", TimeLimitSeconds=60 },
            new() { Title="命令模式", Description="實作命令模式：建立 TextEditor，支援 Write(text) 和 Undo() 操作。依序：Write(\"Hello\"), Write(\" World\"), Undo(), 輸出最終文字。", StarterCode="using System;\nusing System.Collections.Generic;\ninterface ICommand { void Execute(); void Undo(); }\nclass TextEditor {\n    string text = \"\";\n    Stack<ICommand> history = new();\n    public void Execute(ICommand cmd) { cmd.Execute(); history.Push(cmd); }\n    public void Undo() { if (history.Count > 0) history.Pop().Undo(); }\n    public string GetText() => text;\n    // WriteCommand 實作\n    public class WriteCommand : ICommand {\n        TextEditor editor; string added;\n        public WriteCommand(TextEditor e, string t) { editor=e; added=t; }\n        public void Execute() { editor.text += added; }\n        public void Undo() { editor.text = editor.text[..^added.Length]; }\n    }\n}\nclass Program {\n    static void Main() {\n        var editor = new TextEditor();\n        editor.Execute(new TextEditor.WriteCommand(editor, \"Hello\"));\n        editor.Execute(new TextEditor.WriteCommand(editor, \" World\"));\n        editor.Undo();\n        Console.WriteLine(editor.GetText());\n    }\n}", SampleOutput="Hello", ValidationKeywords="ICommand,Execute,Undo,Stack,history,Console.Write,Hello", Difficulty="advanced", TimeLimitSeconds=60 },
            new() { Title="非同步任務管理", Description="建立 3 個模擬非同步任務（延遲 1/2/3 秒後回傳「Task1/2/3 Done」），使用 Task.WhenAll 等待全部完成，輸出每個結果（每行一個，依完成順序）。\n(測試時用 0/0/0 秒，直接輸出)", StarterCode="using System;\nusing System.Threading.Tasks;\nclass Program {\n    static async Task<string> DoTask(int id, int delay) {\n        await Task.Delay(delay);\n        return $\"Task{id} Done\";\n    }\n    static async Task Main() {\n        var tasks = new[] {\n            DoTask(1, 0), DoTask(2, 0), DoTask(3, 0)\n        };\n        var results = await Task.WhenAll(tasks);\n        foreach (var r in results) Console.WriteLine(r);\n    }\n}", SampleOutput="Task1 Done\nTask2 Done\nTask3 Done", ValidationKeywords="async,await,Task.WhenAll,Task.Delay,Console.Write,Task1,Task2,Task3", Difficulty="advanced", TimeLimitSeconds=60 },
            new() { Title="最短路徑 BFS", Description="在 5x5 網格中，從 (0,0) 到 (4,4) 的最短步數（只能上下左右移動，障礙物：(1,1),(2,2),(3,3)）。", StarterCode="using System;\nusing System.Collections.Generic;\nclass Program {\n    static void Main() {\n        int n = 5;\n        bool[,] blocked = new bool[n,n];\n        blocked[1,1] = blocked[2,2] = blocked[3,3] = true;\n        // BFS 找最短路徑\n        int steps = 0;\n        Console.WriteLine(steps);\n    }\n}", SampleOutput="8", ValidationKeywords="Queue,BFS,visited,dx,dy,Console.Write,8", Difficulty="advanced", TimeLimitSeconds=60 },
            new() { Title="記憶體快取裝飾器", Description="實作快取裝飾器模式：建立 CachedCalculator 包裝 SlowCalculator（計算費波那契），第一次計算後快取結果，第二次呼叫直接從快取取得。輸出 Fib(10) 兩次的結果，並輸出第二次是否使用快取（\"From cache: 55\"）。", StarterCode="using System;\nusing System.Collections.Generic;\nclass SlowCalculator {\n    public int Fibonacci(int n) { return n <= 1 ? n : Fibonacci(n-1) + Fibonacci(n-2); }\n}\nclass CachedCalculator {\n    SlowCalculator inner = new();\n    Dictionary<int, int> cache = new();\n    public (int result, bool fromCache) Fibonacci(int n) {\n        // 若有快取直接回傳，否則計算後存入快取\n        return (0, false);\n    }\n}\nclass Program {\n    static void Main() {\n        var calc = new CachedCalculator();\n        var (r1, _) = calc.Fibonacci(10);\n        Console.WriteLine(r1);\n        var (r2, cached) = calc.Fibonacci(10);\n        Console.WriteLine(cached ? $\"From cache: {r2}\" : r2.ToString());\n    }\n}", SampleOutput="55\nFrom cache: 55", ValidationKeywords="Dictionary,cache,fromCache,Fibonacci,Console.Write,55,From cache", Difficulty="advanced", TimeLimitSeconds=60 },
            new() { Title="實作 Pipeline", Description="實作 Pipeline 模式：建立處理管道，串聯三個處理步驟（字串轉大寫、移除空格、加前綴\"[LOG]\"），對輸入 \" hello world \" 輸出最終結果。", StarterCode="using System;\nusing System.Collections.Generic;\nclass Pipeline {\n    List<Func<string, string>> steps = new();\n    public Pipeline Add(Func<string, string> step) { steps.Add(step); return this; }\n    public string Execute(string input) {\n        // 依序執行所有 steps\n        return input;\n    }\n}\nclass Program {\n    static void Main() {\n        var result = new Pipeline()\n            .Add(s => s.ToUpper())\n            .Add(s => s.Trim())\n            .Add(s => \"[LOG] \" + s)\n            .Execute(\" hello world \");\n        Console.WriteLine(result);\n    }\n}", SampleOutput="[LOG] HELLO WORLD", ValidationKeywords="Pipeline,Func,List,foreach,Execute,ToUpper,Trim,Console.Write,[LOG]", Difficulty="advanced", TimeLimitSeconds=60 },
            new() { Title="實作 Result<T> Monad", Description="實作 Result<T> 類型，包含 Ok(value) 和 Fail(error) 工廠方法，以及 Bind 方法串聯操作。測試：Ok(10) → Bind(x => x>5 ? Ok(x*2) : Fail(\"too small\")) → Bind(x => Ok(x+\", success\"))，輸出最終 Value。", StarterCode="using System;\nclass Result<T> {\n    public T? Value { get; private set; }\n    public string? Error { get; private set; }\n    public bool IsSuccess { get; private set; }\n    public static Result<T> Ok(T v) => new() { Value=v, IsSuccess=true };\n    public static Result<T> Fail(string e) => new() { Error=e, IsSuccess=false };\n    public Result<U> Bind<U>(Func<T, Result<U>> f) {\n        // 若失敗則傳遞錯誤，否則執行 f\n        return Result<U>.Fail(\"\");\n    }\n}\nclass Program {\n    static void Main() {\n        var r = Result<int>.Ok(10)\n            .Bind(x => x > 5 ? Result<int>.Ok(x * 2) : Result<int>.Fail(\"too small\"))\n            .Bind(x => Result<string>.Ok($\"{x}, success\"));\n        Console.WriteLine(r.Value);\n    }\n}", SampleOutput="20, success", ValidationKeywords="Result,IsSuccess,Bind,Ok,Fail,Func,Console.Write,20", Difficulty="advanced", TimeLimitSeconds=60 },
            new() { Title="工作流引擎", Description="實作簡單工作流引擎：定義 WorkflowStep 介面，建立 ValidateStep（檢查輸入非空）、TransformStep（轉大寫）、LogStep（加時間戳前綴）三個步驟，對輸入 \"hello\" 執行工作流，輸出最終結果（忽略實際時間，用 [2024] 代替）。", StarterCode="using System;\nusing System.Collections.Generic;\ninterface IWorkflowStep {\n    string Execute(string input);\n}\nclass ValidateStep : IWorkflowStep {\n    public string Execute(string input) => string.IsNullOrEmpty(input) ? throw new Exception(\"Empty\") : input;\n}\nclass TransformStep : IWorkflowStep {\n    public string Execute(string input) => input.ToUpper();\n}\nclass LogStep : IWorkflowStep {\n    public string Execute(string input) => $\"[2024] {input}\";\n}\nclass Workflow {\n    List<IWorkflowStep> steps = new();\n    public Workflow Add(IWorkflowStep s) { steps.Add(s); return this; }\n    public string Run(string input) {\n        // 依序執行所有步驟\n        return input;\n    }\n}\nclass Program {\n    static void Main() {\n        var result = new Workflow()\n            .Add(new ValidateStep())\n            .Add(new TransformStep())\n            .Add(new LogStep())\n            .Run(\"hello\");\n        Console.WriteLine(result);\n    }\n}", SampleOutput="[2024] HELLO", ValidationKeywords="IWorkflowStep,Workflow,Execute,foreach,ToUpper,Console.Write,[2024] HELLO", Difficulty="advanced", TimeLimitSeconds=60 },
        };

